use std::mem;

struct ByteChunk(u8);
struct FloatView(f32);

fn reinterpret_data(bytes: &[u8]) -> Result<FloatView, &'static str> {
    if bytes.len() < mem::size_of::<f32>() {
        return Err("Not enough bytes to view as float");
    }

    let ptr = unsafe { bytes.as_ptr() };
    let float_ptr: *const f32 = ptr.cast();

    let value = unsafe { *float_ptr };
    Ok(FloatView(value))
}

