use std::collections::VecDeque;
use std::sync::{Arc, Mutex};

struct RigidBody {
    id: u32,
    position: (f64, f64),
}

struct CollisionState {
    bodies: Vec<RigidBody>,
    accumulated_force: (f64, f64),
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let shared_state = Arc::new(Mutex::new(CollisionState {
        bodies: vec![],
        accumulated_force: (0.0, 0.0),
    }));

    let state_clone1 = Arc::clone(&shared_state);
    let handle1 = std::thread::spawn(move || {
        println!("Thread 1 starting calculations...");
        let mut state = state_clone1.lock().unwrap();
        state.bodies.push(RigidBody { id: 1, position: (1.0, 2.0) });
        std::thread::sleep(std::time::Duration::from_millis(50));
        let mut state = state_clone1.lock().unwrap();
        state.accumulated_force.0 += 10.0;
        println!("Thread 1 finished writing data.");
    });

    let state_clone2 = Arc::clone(&shared_state);
    let handle2 = std::thread::spawn(move || {
        std::thread::sleep(std::time::Duration::from_millis(75));
        println!("Thread 2 starting calculations...");
        let mut state = state_clone2.lock().unwrap();
        state.bodies.push(RigidBody { id: 2, position: (3.0, 4.0) });
        std::thread::sleep(std::time::Duration::from_millis(50));
        let mut state = state_clone2.lock().unwrap();
        state.accumulated_force.1 += 5.0;
        println!("Thread 2 finished writing data.");
    });

    handle1.join().ok();
    handle2.join().ok();

    let final_state = shared_state.lock().unwrap();
    println!("nFinal State:nForce: ({:.1}, {:.1})", 
        final_state.accumulated_force.0, final_state.accumulated_force.1);

    Ok(())
}

use std::thread::sleep;
use std::time::Duration;

struct WebhookPayload {
    url: String,
    data: String,
}

impl WebhookPayload {
    fn new(url: &str, data: &str) -> Self {
        WebhookPayload { 
            url: url.to_string(), 
            data: data.to_string()
        }
    }
}

async fn attempt_delivery(payload: &WebhookPayload) -> bool {
    println!("Attempting delivery to {} with data: {}", payload.url, payload.data);
    // Simulate an external network call that might fail
    if rand::random::<f32>() < 0.7 {
        println!("Delivery succeeded.");
        true
    } else {
        println!("Delivery failed due to transient error.");
        false
    }
}

async fn dispatch_webhook_with_retry(payload: WebhookPayload, max_retries: u32) -> bool {
    let mut current_delay = Duration::from_millis(100);
    for attempt in 0..=max_retries {
        if attempt_delivery(&payload).await {
            return true;
        }

        if attempt == max_retries {
            println!("Maximum retries reached. Failing permanently.");
            return false;
        }

        println!("Waiting before next retry...");
        sleep(current_delay);
        current_delay = current_delay.checked_mul(2).unwrap_or(Duration::from_secs(60));
    }
    false
}

#[tokio::main]
async fn main() {
    let payload = WebhookPayload::new("https://api.example.com/webhook", "user_event_123");
    dispatch_webhook_with_retry(payload, 4).await;
}

use std::mem;

struct TracingRecordHeader { 
    magic_number: u32,
    record_length: usize,
}

fn process_raw_bytes(data: &[u8]) -> Option<TracingRecordHeader> {
    if data.len() < mem::size_of::<TracingRecordHeader>() {
        return None;
    }

    let mut header_bytes = [0u8; std::mem::size_of::<TracingRecordHeader>()];
    header_bytes.copy_from_slice(&data[..std::mem::size_of::<TracingRecordHeader>()]);

    unsafe {
        let header = mem::transmute(header_bytes);
        Some(header)
    }
}

fn main() {
    let mut raw_buffer: Vec<u8> = vec![0xde, 0xad, 0xbe, 0xef, 0x00, 0x12, 0xff, 0x99];
    if let Some(header) = process_raw_bytes(&raw_buffer) {
        println!("Successfully processed header: {:?}", header);
    }
}
